1	// Recall.ai live Teams utterance worker.
2	//
3	// This processes finalized `transcript.data` events, not partial/provisional
4	// STT hypotheses. Each finalized utterance is persisted as a `messages` row for
5	// evidence/backfill, then a tightly gated Oracle pass decides whether a useful
6	// one-question interjection should be posted back to the Teams meeting chat.
7	
8	import { task } from '@trigger.dev/sdk/v3';
9	import { and, desc, eq, gte, inArray, isNull, sql } from 'drizzle-orm';
10	import { z } from 'zod';
11	import { createHash } from 'node:crypto';
12	import { getDirectDb } from '@oracle/db/client';
13	import {
14	  channelParticipants,
15	  channels,
16	  claimEvidence,
17	  employees,
18	  jobRuns,
19	  messages,
20	  modelRuns,
21	  modelRunUsageDetails,
22	  oracleContextPacks,
23	  oracleInterventions,
24	  sectionClaims,
25	  settings,
26	} from '@oracle/db/schema';
27	import {
28	  OracleAIClient,
29	  buildRetrievalPlanFromQuery,
30	  buildStandardAdapters,
31	  getBrainSectionSnippets,
32	  getOracleRoute,
33	  makeBlock,
34	  resolveRouteFromSettings,
35	  searchWithRetrievalPlan,
36	  type RetrievalPlan,
37	  type OracleModelRoute,
38	  type RelevantClaim,
39	} from '@oracle/ai';
40	import { sendRecallChatMessage, RecallTransientSendError } from '../lib/recall';
41	
42	const FALLBACK_INTERVIEW_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
43	const LIVE_PROMPT_VERSION = 'teams-live-recall-1.1.0';
44	const DEFAULT_COOLDOWN_MINUTES = 10;
45	const DEFAULT_MAX_INTERJECTIONS_PER_HOUR = 3;
46	const DEFAULT_MIN_CONFIDENCE_TO_POST = 70;
47	const RECENT_UTTERANCE_LIMIT = 18;
48	const LIVE_RETRIEVAL_TOP_K = 5;
49	const MIN_SECONDS_BETWEEN_LIVE_QUESTIONS = 20;
50	
51	const RecallWordSchema = z.object({
52	  text: z.string(),
53	  start_timestamp: z.object({ relative: z.number().optional() }).optional(),
54	  end_timestamp: z.object({ relative: z.number().nullable().optional() }).nullable().optional(),
55	});
56	
57	const RecallTranscriptDataSchema = z.object({
58	  words: z.array(RecallWordSchema).optional(),
59	  language_code: z.string().optional(),
60	  participant: z
61	    .object({
62	      id: z.union([z.string(), z.number()]).optional(),
63	      name: z.string().nullable().optional(),
64	      email: z.string().nullable().optional(),
65	      is_host: z.boolean().optional(),
66	      platform: z.string().nullable().optional(),
67	      extra_data: z.unknown().optional(),
68	    })
69	    .optional(),
70	});
71	
72	const RecallRealtimeEventSchema = z.object({
73	  event: z.string(),
74	  data: z.object({
75	    data: RecallTranscriptDataSchema.optional(),
76	    transcript: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
77	    recording: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
78	    bot: z.object({ id: z.string().optional(), metadata: z.record(z.string(), z.unknown()).optional() }).optional(),
79	  }),
80	});
81	
82	const PayloadSchema = z.object({
83	  receivedAt: z.string().optional(),
84	  event: RecallRealtimeEventSchema,
85	});
86	
87	const LiveQuestionDecisionSchema = z.object({
88	  shouldAsk: z.boolean(),
89	  question: z.string().optional(),
90	  reason: z.string(),
91	  confidence: z.number().int().min(0).max(100).default(0),
92	  triggerType: z.enum(['possible_contradiction', 'lull_gap', 'direct_mention', 'none']).default('none'),
93	  evidenceClaimIds: z.array(z.string()).default([]),
94	});
95	type LiveQuestionDecision = z.infer<typeof LiveQuestionDecisionSchema>;
96	
97	type LiveRetrievedClaimContext = RelevantClaim & {
98	  evidenceId: string | null;
99	  evidenceQuote: string | null;
100	  sourceMessageId: string | null;
101	  sourceDocumentChunkId: string | null;
102	  sourceExternalRecordId: string | null;
103	};
104	
105	type LiveRetrievalContext = {
106	  plan: RetrievalPlan;
107	  claims: LiveRetrievedClaimContext[];
108	  brainSections: Array<{ sectionId: string; title: string; markdown: string }>;
109	  contextText: string;
110	  includedClaimIds: string[];
111	  includedEvidenceIds: string[];
112	  includedBrainSectionIds: string[];
113	};
114	
115	const LIVE_ORACLE_SYSTEM = `You are the Oracle listening to a live Microsoft Teams meeting for POP Creations / Spruce Line.
116	
117	Your job is to decide whether to ask ONE short clarification question in the meeting chat.
118	
119	Ask only when the live discussion reveals one of these:
120	- a concrete operational rule, exception, handoff, system limitation, or workaround that is unclear;
121	- a concrete business-process question that the team is actively asking and should not lose in the spoken discussion;
122	- a possible contradiction with a recent statement in this same meeting;
123	- a question that would prevent the team from leaving an important process ambiguity unresolved.
124	
125	You may also be given an "Approved company knowledge" block: already-approved operational claims retrieved for the current utterance. Use it only to judge the live discussion:
126	- prefer asking when the current utterance conflicts with, updates, or leaves a concrete gap against that approved knowledge;
127	- when the current utterance is a direct business-process question, the approved knowledge sharpens the clarification question — it never suppresses capturing the question;
128	- never recite the approved knowledge into the meeting chat and never include claim IDs in the question text;
129	- list the claim IDs that actually influenced your decision in evidenceClaimIds (empty if none did).
130	
131	Do not ask because of small talk, greetings, filler, status updates, or incomplete thoughts.
132	Do not ask if the current utterance is too vague.
133	If the current utterance is already a useful business-process question, it is acceptable to restate that question concisely so it is captured in the meeting chat.
134	Do not summarize.
135	Do not answer the meeting.
136	Do not ask more than one question.
137	Keep the question under 220 characters, warm, plain text, and psychologically safe.`;
138	
139	function buildOracleClient(): OracleAIClient {
140	  return new OracleAIClient({
141	    adapters: buildStandardAdapters(),
142	    fallbackOnError: true,
143	  });
144	}
