146	function hashString(s: string): string {
147	  return createHash('sha256').update(s).digest('hex');
148	}
149	
150	function normalizeWords(words: z.infer<typeof RecallWordSchema>[]): string {
151	  return words
152	    .map((w) => w.text)
153	    .join(' ')
154	    .replace(/\s+([,.;:!?])/g, '$1')
155	    .replace(/\s+/g, ' ')
156	    .trim();
157	}
158	
159	function firstOffsetMs(words: z.infer<typeof RecallWordSchema>[]): number {
160	  const start = words[0]?.start_timestamp?.relative;
161	  return typeof start === 'number' ? Math.round(start * 1000) : 0;
162	}
