164	function clientMessageId(args: {
165	  botId: string;
166	  transcriptId: string;
167	  participantId: string;
168	  offsetMs: number;
169	  text: string;
170	}): string {
171	  const digest = createHash('sha256').update(args.text).digest('hex').slice(0, 12);
172	  return `recall-live:${args.botId}:${args.transcriptId}:${args.participantId}:${args.offsetMs}:${digest}`;
173	}
