226	async function loadLiveSettings(db: ReturnType<typeof getDirectDb>): Promise<{
227	  cooldownMinutes: number;
228	  maxInterjectionsPerHour: number;
229	  forceModelPass: boolean;
230	  forcePost: boolean;
231	  disablePostingLimits: boolean;
232	  minConfidenceToPost: number;
233	}> {
234	  const rows = await db
235	    .select({ key: settings.key, value: settings.value })
236	    .from(settings)
237	    .where(sql`${settings.key} in (
238	      'oracle_cooldown_minutes',
239	      'max_oracle_interjections_per_hour',
240	      'teams_live_recall_force_model_pass',
241	      'teams_live_recall_force_post',
242	      'teams_live_recall_disable_posting_limits',
243	      'teams_live_recall_min_confidence_to_post'
244	    )`);
245	  const map = new Map(rows.map((r) => [r.key, r.value]));
246	  return {
247	    cooldownMinutes:
248	      typeof map.get('oracle_cooldown_minutes') === 'number'
249	        ? (map.get('oracle_cooldown_minutes') as number)
250	        : DEFAULT_COOLDOWN_MINUTES,
251	    maxInterjectionsPerHour:
252	      typeof map.get('max_oracle_interjections_per_hour') === 'number'
253	        ? (map.get('max_oracle_interjections_per_hour') as number)
254	        : DEFAULT_MAX_INTERJECTIONS_PER_HOUR,
255	    forceModelPass: map.get('teams_live_recall_force_model_pass') === true,
256	    forcePost: map.get('teams_live_recall_force_post') === true,
257	    disablePostingLimits: map.get('teams_live_recall_disable_posting_limits') === true,
258	    minConfidenceToPost:
259	      typeof map.get('teams_live_recall_min_confidence_to_post') === 'number'
260	        ? (map.get('teams_live_recall_min_confidence_to_post') as number)
261	        : DEFAULT_MIN_CONFIDENCE_TO_POST,
262	  };
263	}
