265	async function channelRateState(
266	  // Accepts a db or transaction handle so the rate state can be re-read inside
267	  // the per-channel advisory lock.
268	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
269	  db: any,
270	  channelId: string,
271	): Promise<{
272	  minutesSinceLast: number | null;
273	  inLastHour: number;
274	}> {
275	  const last = await db
276	    .select({ createdAt: oracleInterventions.createdAt })
277	    .from(oracleInterventions)
278	    .where(eq(oracleInterventions.channelId, channelId))
279	    .orderBy(desc(oracleInterventions.createdAt))
280	    .limit(1);
281	  const minutesSinceLast = last[0]
282	    ? Math.floor((Date.now() - last[0].createdAt.getTime()) / 60_000)
283	    : null;
284	  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
285	  const countRows = await db
286	    .select({ c: sql<number>`count(*)::int` })
287	    .from(oracleInterventions)
288	    .where(and(eq(oracleInterventions.channelId, channelId), gte(oracleInterventions.createdAt, oneHourAgo)));
289	  return { minutesSinceLast, inLastHour: countRows[0]?.c ?? 0 };
290	}
