292	function isWorthModelPass(text: string): boolean {
293	  if (text.length < 40) return false;
294	  return /\b(always|never|usually|not always|exception|approval|approved|send|handoff|handover|Coldlion|ERP|China|factory|routing|Burlington|TJX|Ross|Walmart|Disney|Marvel|licensor|customer|sample|production|shipping|cost|workaround|spreadsheet|process)\b/i.test(text);
295	}
296	
297	function forcedTestQuestion(text: string): string {
298	  const cleaned = stripOracleAddress(text).replace(/^test[:,]?\s*/i, '').replace(/\s+/g, ' ').trim();
299	  if (!cleaned) return 'Quick Oracle test: what should we clarify from the current discussion?';
300	  return cleaned.endsWith('?') ? cleaned : `${cleaned}?`;
301	}
302	
303	function stripOracleAddress(text: string): string {
304	  return text
305	    .replace(/^\s*(hey\s+)?oracle[:,]?\s*/i, '')
306	    .replace(/\s+/g, ' ')
307	    .trim();
308	}
309	
310	function isMetaOracleQuestion(text: string): boolean {
311	  return /\b(oracle|ai|transcription|transcript|record|recording|listen|listening|eavesdropping|bot)\b/i.test(text);
312	}
313	
314	function isDirectBusinessQuestion(text: string): boolean {
315	  const content = stripOracleAddress(text);
316	  if (!content.includes('?')) return false;
317	  if (isMetaOracleQuestion(content)) return false;
318	  return isWorthModelPass(content);
319	}
320	
321	function fallbackClarificationQuestion(text: string): string {
322	  const content = stripOracleAddress(text).replace(/\s+/g, ' ').trim();
323	  if (!content) return 'Can we clarify the business-process question that was just raised?';
324	  return `Can we clarify this process question: ${content}`;
325	}
326	
327	function truncateForPrompt(text: string, maxChars: number): string {
328	  const normalized = text.replace(/\s+/g, ' ').trim();
329	  if (normalized.length <= maxChars) return normalized;
330	  return `${normalized.slice(0, Math.max(0, maxChars - 3)).trimEnd()}...`;
331	}
332	
333	async function loadEvidenceForClaims(
334	  db: ReturnType<typeof getDirectDb>,
335	  claimIds: string[],
336	): Promise<Map<string, {
337	  evidenceId: string;
338	  exactQuote: string;
339	  sourceMessageId: string | null;
340	  sourceDocumentChunkId: string | null;
341	  sourceExternalRecordId: string | null;
342	}>> {
343	  if (claimIds.length === 0) return new Map();
344	
345	  const rows = await db
346	    .select({
347	      evidenceId: claimEvidence.id,
348	      claimId: claimEvidence.claimId,
349	      exactQuote: claimEvidence.exactQuote,
350	      sourceMessageId: claimEvidence.sourceMessageId,
351	      sourceDocumentChunkId: claimEvidence.sourceDocumentChunkId,
352	      sourceExternalRecordId: claimEvidence.sourceExternalRecordId,
353	      createdAt: claimEvidence.createdAt,
354	    })
355	    .from(claimEvidence)
356	    .where(inArray(claimEvidence.claimId, claimIds))
357	    .orderBy(desc(claimEvidence.createdAt));
358	
359	  const byClaim = new Map<string, {
360	    evidenceId: string;
361	    exactQuote: string;
362	    sourceMessageId: string | null;
363	    sourceDocumentChunkId: string | null;
364	    sourceExternalRecordId: string | null;
365	  }>();
366	  for (const row of rows) {
367	    if (byClaim.has(row.claimId)) continue;
368	    byClaim.set(row.claimId, {
369	      evidenceId: row.evidenceId,
370	      exactQuote: row.exactQuote,
371	      sourceMessageId: row.sourceMessageId,
372	      sourceDocumentChunkId: row.sourceDocumentChunkId,
373	      sourceExternalRecordId: row.sourceExternalRecordId,
374	    });
375	  }
376	  return byClaim;
377	}
