379	async function buildLiveRetrievalContext(args: {
380	  db: ReturnType<typeof getDirectDb>;
381	  currentUtterance: string;
382	  recentContext: string;
383	}): Promise<LiveRetrievalContext | null> {
384	  const retrievalQuery = [
385	    stripOracleAddress(args.currentUtterance),
386	    args.recentContext ? `Recent meeting context:\n${args.recentContext}` : '',
387	  ].filter(Boolean).join('\n\n');
388	  if (!retrievalQuery) return null;
389	
390	  try {
391	    const plan = buildRetrievalPlanFromQuery(retrievalQuery, { topK: LIVE_RETRIEVAL_TOP_K });
392	    const claims = await searchWithRetrievalPlan(args.db, plan);
393	    const evidenceByClaim = await loadEvidenceForClaims(args.db, claims.map((c) => c.id));
394	    const sectionRows = claims.length > 0
395	      ? await args.db
396	          .select({ sectionId: sectionClaims.sectionId })
397	          .from(sectionClaims)
398	          .where(inArray(sectionClaims.claimId, claims.map((c) => c.id)))
399	          .limit(2)
400	      : [];
401	    const sectionIds = Array.from(new Set(sectionRows.map((r) => r.sectionId))).slice(0, 2);
402	    const brainSnippets = await getBrainSectionSnippets(args.db, sectionIds);
403	
404	    const enrichedClaims: LiveRetrievedClaimContext[] = claims.map((claim) => {
405	      const evidence = evidenceByClaim.get(claim.id);
406	      return {
407	        ...claim,
408	        evidenceId: evidence?.evidenceId ?? null,
409	        evidenceQuote: evidence?.exactQuote ?? null,
410	        sourceMessageId: evidence?.sourceMessageId ?? null,
411	        sourceDocumentChunkId: evidence?.sourceDocumentChunkId ?? null,
412	        sourceExternalRecordId: evidence?.sourceExternalRecordId ?? null,
413	      };
414	    });
415	
416	    const claimsText = enrichedClaims.length > 0
417	      ? enrichedClaims.map((claim, i) => {
418	          const quote = claim.evidenceQuote
419	            ? ` Evidence: "${truncateForPrompt(claim.evidenceQuote, 220)}"`
420	            : '';
421	          return `[C${i + 1}] ${truncateForPrompt(claim.summary, 260)} (impact ${claim.impactScore}, confidence ${claim.confidenceScore}).${quote}`;
422	        }).join('\n')
423	      : 'No approved claims matched this live context.';
424	    const brainText = brainSnippets.length > 0
425	      ? brainSnippets.map((section, i) =>
426	          `[B${i + 1}] ${section.title}: ${truncateForPrompt(section.markdown, 420)}`,
427	        ).join('\n')
428	      : 'No linked Brain sections found for retrieved claims.';
429	    const contextText = `Approved claims:\n${claimsText}\n\nLinked Brain sections:\n${brainText}`;
430	
431	    return {
432	      plan,
433	      claims: enrichedClaims,
434	      brainSections: brainSnippets,
435	      contextText,
436	      includedClaimIds: enrichedClaims.map((c) => c.id),
437	      includedEvidenceIds: enrichedClaims.flatMap((c) => c.evidenceId ? [c.evidenceId] : []),
438	      includedBrainSectionIds: brainSnippets.map((s) => s.sectionId),
439	    };
440	  } catch (err) {
441	    const cause = err instanceof Error && err.cause instanceof Error ? ` cause: ${err.cause.message}` : '';
442	    console.warn(
443	      '[teams-live-recall-utterance] retrieval failed; deciding without approved-knowledge context',
444	      `${err instanceof Error ? err.message.slice(0, 300) : String(err)}${cause}`,
445	    );
446	    return null;
447	  }
448	}
