450	async function decideLiveQuestion(args: {
451	  db: ReturnType<typeof getDirectDb>;
452	  client: OracleAIClient;
453	  route: OracleModelRoute;
454	  channelId: string;
455	  currentUtterance: string;
456	  speakerName: string | null;
457	}): Promise<{
458	  decision: LiveQuestionDecision;
459	  modelRunId: string | null;
460	  retrievalContext: LiveRetrievalContext | null;
461	}> {
462	  const recent = await args.db
463	    .select({ id: messages.id, content: messages.content, metadataJson: messages.metadataJson, createdAt: messages.createdAt })
464	    .from(messages)
465	    .where(and(eq(messages.channelId, args.channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
466	    .orderBy(desc(messages.createdAt))
467	    .limit(RECENT_UTTERANCE_LIMIT);
468	
469	  const recentContext = recent
470	    .slice()
471	    .reverse()
472	    .map((m, i) => {
473	      const meta = (m.metadataJson ?? {}) as { speaker?: string };
474	      return `[${i + 1}] ${meta.speaker ? `${meta.speaker}: ` : ''}${m.content}`;
475	    })
476	    .join('\n');
477	  const retrievalContext = await buildLiveRetrievalContext({
478	    db: args.db,
479	    currentUtterance: args.currentUtterance,
480	    recentContext,
481	  });
482	  const retrievalContextText = retrievalContext?.contextText ?? 'Approved-knowledge retrieval was unavailable for this utterance.';
483	  const userContent = `Recent finalized meeting utterances (oldest first):
484	${recentContext}
485	
486	Retrieved approved Oracle knowledge:
487	${retrievalContextText}
488	
489	Current utterance to evaluate:
490	${args.speakerName ? `${args.speakerName}: ` : ''}${args.currentUtterance}`;
491	
492	  const blocks = [
493	    makeBlock({
494	      id: 'sys',
495	      label: 'Teams live Oracle decision system',
496	      kind: 'stable_system',
497	      content: LIVE_ORACLE_SYSTEM,
498	      cacheEligible: true,
499	      reasonIncluded: 'live Teams meeting interjection decision',
500	    }),
501	    ...(retrievalContext
502	      ? [
503	          makeBlock({
504	            id: 'retrieved-claims',
505	            label: 'Retrieved approved Oracle knowledge',
506	            kind: 'retrieved_context' as const,
507	            content: retrievalContext.contextText,
508	            cacheEligible: false,
509	            reasonIncluded: 'approved claims and Brain sections retrieved for live Teams decision',
510	          }),
511	        ]
512	      : []),
513	    makeBlock({
514	      id: 'utterances',
515	      label: 'Recent finalized utterances',
516	      kind: 'dynamic_input',
517	      content: userContent,
518	      cacheEligible: false,
519	      reasonIncluded: 'rolling live Teams transcript window',
520	    }),
521	  ];
522	
523	  const [contextPack] = await args.db
524	    .insert(oracleContextPacks)
525	    .values({
526	      taskType: 'interview_chat',
527	      routeId: args.route.routeId,
528	      promptVersion: LIVE_PROMPT_VERSION,
529	      stablePrefixHash: hashString(LIVE_ORACLE_SYSTEM),
530	      retrievedContextHash: retrievalContext ? hashString(retrievalContext.contextText) : null,
531	      dynamicInputHash: hashString(userContent),
532	      blocksJson: blocks.map((b) => ({
533	        id: b.id,
534	        kind: b.kind,
535	        hash: b.hash,
536	        tokenEstimate: b.tokenEstimate,
537	      })),
538	      selectedDomains: retrievalContext
539	        ? retrievalContext.plan.searchScope === 'domain_filtered'
540	          ? retrievalContext.plan.topDomainHints
541	          : [retrievalContext.plan.searchScope === 'global_explicit' ? '_global_explicit' : '_global_fallback']
542	        : [],
543	      selectedSourceTypes: retrievalContext?.includedBrainSectionIds.length
544	        ? ['approved_claim', 'brain_section', 'message']
545	        : retrievalContext ? ['approved_claim', 'message'] : ['message'],
546	      selectedProcessStages: retrievalContext?.plan.processStageHints ?? [],
547	      selectedEntityIds: retrievalContext?.plan.requiredEntities.map((e) => `${e.entityType}:${e.canonicalValue}`) ?? [],
548	      includedMessageIds: recent.map((m) => m.id),
549	      includedClaimIds: retrievalContext?.includedClaimIds ?? [],
550	    })
551	    .returning({ id: oracleContextPacks.id });
552	  if (!contextPack) throw new Error('failed to insert oracle_context_packs row');
553	
554	  const callStartedAt = Date.now();
555	  let modelRunId: string | null = null;
556	  try {
557	    const result = await args.client.runObject<LiveQuestionDecision>({
558	      taskType: 'interview_chat',
559	      routeId: args.route.routeId,
560	      promptVersion: LIVE_PROMPT_VERSION,
561	      blocks,
