58	interface Cue {
59	  speaker: string | null;
60	  text: string;
61	  offsetMs: number;
62	}
63	
64	function vttTimeToMs(t: string): number {
65	  const p = t.trim().split(':').map((x) => Number.parseFloat(x) || 0);
66	  if (p.length === 3) {
67	    return Math.round(((p[0] ?? 0) * 3600 + (p[1] ?? 0) * 60 + (p[2] ?? 0)) * 1000);
68	  }
69	  if (p.length === 2) {
70	    return Math.round(((p[0] ?? 0) * 60 + (p[1] ?? 0)) * 1000);
71	  }
72	  return 0;
73	}
74	
75	/** Parse Teams WebVTT into cues. Handles `<v Speaker Name>text</v>` voice tags. */
76	export function parseVtt(vtt: string): Cue[] {
77	  const cues: Cue[] = [];
78	  const blocks = vtt.replace(/\r/g, '').split(/\n\n+/);
79	  for (const block of blocks) {
80	    const lines = block.split('\n').filter((l) => l.trim() !== '');
81	    const timingIdx = lines.findIndex((l) => l.includes('-->'));
82	    if (timingIdx === -1) continue;
83	    const timingLine = lines[timingIdx];
84	    if (!timingLine) continue;
85	    const offsetMs = vttTimeToMs(timingLine.split('-->')[0] ?? '');
86	
87	    let text = lines.slice(timingIdx + 1).join(' ').trim();
88	    let speaker: string | null = null;
89	    const voice = text.match(/<v\s+([^>]+)>([\s\S]*?)<\/v>/i);
90	    if (voice) {
91	      speaker = (voice[1] ?? '').trim();
92	      text = (voice[2] ?? '').trim();
93	    } else {
94	      text = text.replace(/<[^>]+>/g, '').trim();
95	    }
96	    if (text) cues.push({ speaker, text, offsetMs });
97	  }
98	  return cues;
99	}
100	
101	/** Merge consecutive cues from the same speaker into one fuller utterance. */
102	function mergeBySpeaker(cues: Cue[]): Cue[] {
103	  const out: Cue[] = [];
104	  for (const c of cues) {
105	    const last = out[out.length - 1];
106	    if (last && last.speaker === c.speaker) {
107	      last.text = `${last.text} ${c.text}`.trim();
108	    } else {
109	      out.push({ ...c });
110	    }
111	  }
112	  return out;
113	}
