115	/** Stable id for this transcript, used for idempotency + provenance. */
116	function deriveTranscriptId(p: IngestionPayload): string {
117	  const src = p.transcriptContentUrl || p.resourcePath || '';
118	  const m = src.match(/transcripts[('/]+([^')/]+)/i);
119	  if (m && m[1]) {
120	    // Scheduled online-meeting transcript ids are long base64 blobs (~230
121	    // chars). clientMessageId = `teams:<id>:<n>` must fit messages.client_message_id
122	    // (varchar(255)), so hash anything long to a stable 32-char digest. Short
123	    // ad-hoc ids pass through unchanged (preserves existing dedup keys). The
124	    // full id is still kept verbatim in messages.metadata_json.transcriptId.
125	    return m[1].length > 64 ? createHash('sha256').update(m[1]).digest('hex').slice(0, 32) : m[1];
126	  }
127	  return createHash('sha256')
128	    .update(src + (p.meetingId ?? '') + (p.callId ?? ''))
129	    .digest('hex')
130	    .slice(0, 32);
131	}
