133	export const teamsTranscriptIngestionTask = task({
134	  id: 'teams-transcript-ingestion',
135	  maxDuration: 60 * 5,
136	  run: async (payload: IngestionPayload, { ctx }) => {
137	    const db = getDirectDb();
138	    const [jobRun] = await db
139	      .insert(jobRuns)
140	      .values({
141	        triggerRunId: ctx.run.id,
142	        jobType: 'teams-transcript-ingestion',
143	        status: 'running',
144	        startedAt: new Date(),
145	        inputJson: payload,
146	      })
147	      .returning({ id: jobRuns.id });
148	    if (!jobRun) throw new Error('[teams-transcript-ingestion] failed to insert job_runs row');
149	
150	    try {
151	      const transcriptId = deriveTranscriptId(payload);
152	
153	      // Idempotency: bail if we've already ingested this transcript.
154	      const already = await db
155	        .select({ id: messages.id })
156	        .from(messages)
157	        .where(sql`${messages.clientMessageId} like ${`teams:${transcriptId}:%`}`)
158	        .limit(1);
159	      if (already.length > 0) {
160	        const out = { skipped: true, reason: 'already ingested', transcriptId };
161	        await db
162	          .update(jobRuns)
163	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
164	          .where(eq(jobRuns.id, jobRun.id));
165	        return { ok: true, ...out };
166	      }
167	
168	      const vtt = await fetchTranscriptVtt(
169	        payload.transcriptContentUrl ?? null,
170	        payload.resourcePath ?? null,
171	      );
172	      const cues = mergeBySpeaker(parseVtt(vtt));
173	
174	      if (cues.length === 0) {
175	        const out = { transcriptId, messages: 0, reason: 'empty transcript' };
176	        await db
177	          .update(jobRuns)
178	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
179	          .where(eq(jobRuns.id, jobRun.id));
180	        return { ok: true, ...out };
181	      }
182	
183	      // Speaker → employee resolution.
184	      // Primary path: VTT display name -> M365 directory email -> employee by
185	      // email (employees.email or any employee_identities.email). This mirrors
186	      // the auth linker's email-based identity model and is robust to display
187	      // names that don't equal employees.name. Fallback: display-name match.
188	      const emps = await db
189	        .select({ id: employees.id, name: employees.name, email: employees.email })
190	        .from(employees);
191	      const idents = await db
192	        .select({ employeeId: employeeIdentities.employeeId, email: employeeIdentities.email })
193	        .from(employeeIdentities);
194	      const byName = new Map<string, string>();
195	      const byEmail = new Map<string, string>();
196	      for (const e of emps) {
197	        if (e.name) byName.set(e.name.trim().toLowerCase(), e.id);
198	        if (e.email) byEmail.set(e.email.trim().toLowerCase(), e.id);
199	      }
200	      for (const i of idents) {
201	        const key = i.email?.trim().toLowerCase();
202	        if (key && !byEmail.has(key)) byEmail.set(key, i.employeeId);
203	      }
204	      let displayNameToEmail = new Map<string, string>();
205	      try {
206	        displayNameToEmail = await listDisplayNameToEmail();
207	      } catch (err) {
208	        console.warn('[teams-transcript-ingestion] directory lookup failed; using name match only', err);
209	      }
210	      const resolveExisting = (speaker: string): string | null => {
211	        const key = speaker.trim().toLowerCase();
212	        const email = displayNameToEmail.get(key);
213	        if (email) {
214	          const viaEmail = byEmail.get(email);
215	          if (viaEmail) return viaEmail;
216	        }
217	        return byName.get(key) ?? null;
218	      };
219	
220	      // Resolve each distinct speaker once. Bootstrap-create an employee for a
221	      // speaker who maps to an @popcre.com directory user but isn't onboarded
222	      // yet — mirrors the auth linker's email-based bootstrap. Scoped to
223	      // @popcre.com so external/guest participants stay unattributed (null).
224	      const resolvedBySpeaker = new Map<string, string | null>();
225	      const bootstrapped: string[] = [];
226	      const distinctSpeakers = [
227	        ...new Set(cues.map((c) => c.speaker).filter((s): s is string => Boolean(s))),
228	      ];
229	      for (const speaker of distinctSpeakers) {
230	        let empId = resolveExisting(speaker);
231	        if (!empId) {
232	          const email = displayNameToEmail.get(speaker.trim().toLowerCase());
233	          if (email && email.endsWith('@popcre.com')) {
234	            const [created] = await db
235	              .insert(employees)
236	              .values({ name: speaker.trim(), email, role: 'Employee' })
237	              .onConflictDoNothing({ target: employees.email })
238	              .returning({ id: employees.id });
239	            if (created) {
240	              empId = created.id;
241	              bootstrapped.push(email);
242	            } else {
243	              const [ex] = await db
244	                .select({ id: employees.id })
245	                .from(employees)
246	                .where(eq(employees.email, email))
247	                .limit(1);
248	              empId = ex?.id ?? null;
249	            }
250	            if (empId) byEmail.set(email, empId);
251	          }
252	        }
253	        resolvedBySpeaker.set(speaker, empId);
254	      }
255	
256	      // Anchor to the real meeting time when known (picker passes it); fall back
257	      // to now. This keeps ingested past meetings from looking "live" to
258	      // lull-interjection (which keys off recent message timestamps).
259	      const parsedMeetingTime = payload.meetingTime ? Date.parse(payload.meetingTime) : NaN;
260	      const base = Number.isFinite(parsedMeetingTime) ? parsedMeetingTime : Date.now();
261	      const [channel] = await db
262	        .insert(channels)
263	        .values({
264	          name: `Teams call ${new Date(base).toISOString().slice(0, 16).replace('T', ' ')} UTC`,
265	          isGroupChat: true,
266	          status: 'active',
267	        })
268	        .returning({ id: channels.id });
269	      if (!channel) throw new Error('failed to create channel for transcript');
270	
271	      // Persist the raw VTT so the entire pipeline (parsing → messages →
272	      // extraction → synthesis) stays re-runnable from true source even after
273	      // Microsoft expires the transcript. The `messages` rows are already a
274	      // lossy transform (merged turns, resolved speakers); this is the raw.
275	      await db.execute(sql`
276	        insert into raw_transcripts (channel_id, call_id, transcript_id, vtt)
277	        values (${channel.id}::uuid, ${payload.callId ?? null}, ${transcriptId}, ${vtt})
278	        on conflict (transcript_id) do nothing
279	      `);
280	
281	      const participantIds = new Set<string>();
282	      const rows = cues.map((c, i) => {
283	        const employeeId = c.speaker ? (resolvedBySpeaker.get(c.speaker) ?? null) : null;
284	        if (employeeId) participantIds.add(employeeId);
285	        return {
286	          channelId: channel.id,
287	          employeeId,
288	          role: 'user' as const,
289	          content: c.text,
290	          clientMessageId: `teams:${transcriptId}:${i}`,
291	          // 'pending' → the claim-extraction cron picks it up. Ingestion only
292	          // happens because an admin chose this meeting in the picker, so the
293	          // choice IS the go-ahead (no separate extraction gate).
294	          extractionStatus: 'pending' as const,
295	          createdAt: new Date(base + c.offsetMs),
296	          metadataJson: {
297	            source: 'teams_transcript',
298	            transcriptId,
299	            meetingId: payload.meetingId ?? null,
300	            callId: payload.callId ?? null,
301	            speaker: c.speaker,
302	            offsetMs: c.offsetMs,
303	            resolvedEmployeeId: employeeId,
304	          },
305	        };
306	      });
307	
308	      await db.insert(messages).values(rows);
309	      for (const employeeId of participantIds) {
310	        await db
311	          .insert(channelParticipants)
312	          .values({ channelId: channel.id, employeeId })
313	          .onConflictDoNothing();
314	      }
315	
316	      // Flip the discovery row to 'ingested' so the picker reflects it and the
317	      // same meeting isn't offered again. Keyed by the full Graph transcript id
318	      // (meeting_transcripts.transcript_id), which the picker passes verbatim.
319	      if (payload.discoveryTranscriptId) {
320	        await db.execute(sql`
321	          update meeting_transcripts
322	          set status = 'ingested', ingested_channel_id = ${channel.id}::uuid, ingested_at = now()
323	          where transcript_id = ${payload.discoveryTranscriptId}
324	        `);
325	      }
326	
327	      const out = {
328	        transcriptId,
329	        channelId: channel.id,
330	        messages: rows.length,
331	        speakersResolved: participantIds.size,
332	        speakersTotal: new Set(cues.map((c) => c.speaker)).size,
333	        bootstrapped: bootstrapped.length,
334	      };
335	      await db
336	        .update(jobRuns)
337	        .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
338	        .where(eq(jobRuns.id, jobRun.id));
339	      return { ok: true, ...out };
340	    } catch (err) {
341	      const errMsg = err instanceof Error ? err.message : String(err);
342	      await db
343	        .update(jobRuns)
344	        .set({ status: 'failed', finishedAt: new Date(), error: errMsg })
345	        .where(eq(jobRuns.id, jobRun.id));
346	      throw err;
347	    }
348	  },
349	});
