309	  dbOrTx: any,
310	  channelId: string,
311	  now: Date,
312	): Promise<{ minutesSinceLastOracleInterjection: number | null; interjectionsInLastHour: number }> {
313	  const lastInterventionRows = await dbOrTx
314	    .select({ createdAt: oracleInterventions.createdAt })
315	    .from(oracleInterventions)
316	    .where(eq(oracleInterventions.channelId, channelId))
317	    .orderBy(desc(oracleInterventions.createdAt))
