319	  const minutesSinceLastOracleInterjection =
320	    lastInterventionRows.length > 0 && lastInterventionRows[0]
321	      ? Math.floor((now.getTime() - lastInterventionRows[0].createdAt.getTime()) / 60_000)
322	      : null;
323	  const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
324	  const countRows = await dbOrTx
325	    .select({ c: sql<number>`count(*)::int` })
326	    .from(oracleInterventions)
327	    .where(
328	      and(
329	        eq(oracleInterventions.channelId, channelId),
330	        gte(oracleInterventions.createdAt, oneHourAgo),
331	      ),
332	    );
333	  return {
334	    minutesSinceLastOracleInterjection,
335	    interjectionsInLastHour: countRows[0]?.c ?? 0,
336	  };
337	}
