339	// ─── Drafting via OracleAIClient.runText (interview route) ──────────────────
340	async function draftLullQuestion(
341	  db: ReturnType<typeof getDirectDb>,
342	  client: OracleAIClient,
343	  route: OracleModelRoute,
344	  gap: RelevantOpenGap,
345	  recentMessageExcerpts: string[],
346	): Promise<{ text: string; modelRunId: string | null }> {
347	  const recentContext = recentMessageExcerpts.length === 0
348	    ? '(no recent messages)'
349	    : recentMessageExcerpts.map((m, i) => `[${i + 1}] ${m}`).join('\n');
350	
351	  const userMessage = `Open question to ask: ${gap.questionToAsk}
352	Why it matters: ${gap.whyItMatters}
353	
354	Recent messages in this channel (oldest first, for tone reference — do not directly quote):
355	${recentContext}`;
356	
357	  const blocks = [
358	    makeBlock({
359	      id: 'sys',
360	      label: 'Lull-interjection system prompt',
361	      kind: 'stable_system',
362	      content: LULL_DRAFT_SYSTEM,
363	      cacheEligible: true,
364	      reasonIncluded: 'spec 5.1 Rule 2 — lull interjection drafting',
365	    }),
366	    makeBlock({
367	      id: 'gap-input',
368	      label: 'Gap + recent context',
369	      kind: 'dynamic_input',
370	      content: userMessage,
371	      cacheEligible: false,
372	      reasonIncluded: 'current gap and recent messages',
373	    }),
374	  ];
375	
376	  const callStartedAt = Date.now();
377	  let modelRunId: string | null = null;
378	  try {
379	    const result = await client.runText({
380	      taskType: 'gap_generation',
381	      routeId: route.routeId,
382	      promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
383	      blocks,
384	      providerOptions: { temperature: 0.4 },
385	    });
386	    const latencyMs = Date.now() - callStartedAt;
387	    const actualRouteId = result.routeId ?? route.routeId;
388	    const actualProvider = result.provider ?? route.provider;
389	    const actualModelId = result.modelId ?? route.modelId;
390	
391	    const [contextPack] = await db
392	      .insert(oracleContextPacks)
393	      .values({
394	        taskType: 'gap_generation',
395	        routeId: route.routeId,
396	        promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
397	        stablePrefixHash: hashString(LULL_DRAFT_SYSTEM),
398	        dynamicInputHash: hashString(userMessage),
399	        blocksJson: blocks.map((b) => ({
400	          id: b.id,
401	          kind: b.kind,
402	          hash: b.hash,
403	          tokenEstimate: b.tokenEstimate,
404	        })),
405	        includedGapIds: [gap.id],
406	      })
407	      .returning({ id: oracleContextPacks.id });
408	    if (!contextPack) throw new Error('failed to insert oracle_context_packs row');
409	
410	    const [modelRun] = await db
411	      .insert(modelRuns)
412	      .values({
413	        taskType: 'lull-interjection',
414	        model: actualModelId,
415	        provider: actualProvider,
416	        promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
417	        inputHash: hashString(LULL_DRAFT_SYSTEM),
418	        inputTokens: result.usage.inputTokens ?? null,
419	        outputTokens: result.usage.outputTokens ?? null,
420	        latencyMs,
421	        success: true,
422	      })
423	      .returning({ id: modelRuns.id });
424	    if (!modelRun) throw new Error('failed to insert model_runs row');
425	    modelRunId = modelRun.id;
426	
427	    await db.insert(modelRunUsageDetails).values({
428	      modelRunId: modelRun.id,
429	      contextPackId: contextPack.id,
430	      routeId: actualRouteId,
431	      inputTokens: result.usage.inputTokens ?? null,
432	      outputTokens: result.usage.outputTokens ?? null,
433	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
434	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
435	      reasoningTokens: result.usage.reasoningTokens ?? null,
436	      providerRequestId: result.usage.providerRequestId ?? null,
437	      rawUsageJson: (result.usage.rawUsageJson ?? null) as Record<string, unknown> | null,
438	      fellBackFromRouteId: result.fellBackFromRouteId ?? null,
439	      fallbackReason: result.fallbackReason ?? null,
440	    });
441	
442	    await db
443	      .update(oracleContextPacks)
444	      .set({ modelRunId: modelRun.id })
445	      .where(eq(oracleContextPacks.id, contextPack.id));
446	
447	    const text = (result.text ?? '').trim();
448	    if (text.length === 0) {
449	      throw new Error('drafting returned empty text');
450	    }
451	    return { text, modelRunId };
452	  } catch (err) {
453	    const latencyMs = Date.now() - callStartedAt;
454	    const message = err instanceof Error ? err.message : String(err);
455	    try {
456	      const [modelRun] = await db
457	        .insert(modelRuns)
458	        .values({
459	          taskType: 'lull-interjection',
460	          model: route.modelId,
461	          provider: route.provider,
462	          promptVersion: LULL_INTERJECTION_PROMPT_VERSION,
463	          latencyMs,
464	          success: false,
465	          error: message,
466	        })
467	        .returning({ id: modelRuns.id });
468	      modelRunId = modelRun?.id ?? null;
469	    } catch {
470	      /* swallow */
471	    }
472	    throw err;
473	  }
474	}
