476	// ─── Per-channel processing ─────────────────────────────────────────────────
477	interface ChannelOutcome {
478	  channelId: string;
479	  decision: 'ask' | 'skip';
480	  reasonCode?: string;
481	  interjectionMessageId?: string;
482	  gapId?: string;
483	  errorMessage?: string;
484	}
485	
486	async function processChannel(
487	  db: ReturnType<typeof getDirectDb>,
488	  client: OracleAIClient,
489	  route: OracleModelRoute,
490	  channel: { id: string; isGroupChat: boolean },
491	  settings: LullSettings,
492	  now: Date,
493	): Promise<ChannelOutcome> {
494	  const ctx = await loadChannelContext(db, channel.id, channel.isGroupChat, now);
495	
496	  // No user messages ever → nothing to interrupt; treat as long lull but skip
497	  // because the channel hasn't started a conversation yet.
498	  if (ctx.secondsSinceLastUserMessage === null) {
499	    return {
500	      channelId: channel.id,
501	      decision: 'skip',
502	      reasonCode: 'no_user_messages_yet',
503	    };
504	  }
505	
506	  const decisionInput: LullInterjectionInput = {
507	    secondsSinceLastUserMessage: ctx.secondsSinceLastUserMessage,
508	    lullWindowSeconds: settings.lullWindowSeconds,
509	    isAnyoneTyping: ctx.isAnyoneTyping,
510	    minutesSinceLastOracleInterjection: ctx.minutesSinceLastOracleInterjection,
511	    oracleCooldownMinutes: settings.oracleCooldownMinutes,
512	    interjectionsInLastHour: ctx.interjectionsInLastHour,
513	    maxOracleInterjectionsPerHour: settings.maxOracleInterjectionsPerHour,
514	    enableGroupChatLullQuestions: settings.enableGroupChatLullQuestions,
515	    channelKind: channel.isGroupChat ? 'group' : 'dm',
516	    topRelevantOpenGap: ctx.topRelevantOpenGap,
517	  };
518	
519	  const decision = decideLullInterjection(decisionInput);
520	
521	  if (decision.decision === 'skip') {
522	    return {
523	      channelId: channel.id,
524	      decision: 'skip',
525	      reasonCode: decision.reasonCode,
526	    };
527	  }
528	
529	  // decision === 'ask' — draft + post.
530	  try {
531	    if (!ctx.topRelevantOpenGap) {
532	      // The decider already enforces this, but TS doesn't know.
533	      return { channelId: channel.id, decision: 'skip', reasonCode: 'no_relevant_gap' };
534	    }
535	    const gap = ctx.topRelevantOpenGap;
536	
537	    // Draft OUTSIDE the lock (don't hold the advisory lock across the LLM call).
538	    const drafted = await draftLullQuestion(db, client, route, gap, ctx.recentMessageExcerpts);
539	
540	    // Commit inside a transaction guarded by a per-channel advisory lock so two
541	    // concurrent runs can't both blow past the per-hour interjection cap on the
542	    // same channel. Re-read the rate/cooldown state inside the lock and re-run
543	    // the decider; also claim the gap atomically so two workers can't ask the
544	    // same gap. If the lock is contended or the re-check/gap-claim fails, skip.
545	    return await db.transaction(async (tx) => {
546	      const lockRes = await tx.execute<{ locked: boolean }>(
547	        sql`SELECT pg_try_advisory_xact_lock(hashtext(${channel.id})) AS locked`,
548	      );
549	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
550	      const lockRows: Array<{ locked: boolean }> = (lockRes as any).rows ?? (lockRes as any);
551	      if (lockRows[0]?.locked !== true) {
552	        return { channelId: channel.id, decision: 'skip' as const, reasonCode: 'skipped: lock_contended' };
553	      }
554	
555	      // Re-read cooldown + rate-cap state inside the lock and re-decide.
556	      const recheck = await reloadInterjectionRateState(tx, channel.id, new Date());
557	      const recheckDecision = decideLullInterjection({
558	        ...decisionInput,
559	        minutesSinceLastOracleInterjection: recheck.minutesSinceLastOracleInterjection,
560	        interjectionsInLastHour: recheck.interjectionsInLastHour,
561	      });
562	      if (recheckDecision.decision === 'skip') {
563	        return { channelId: channel.id, decision: 'skip' as const, reasonCode: recheckDecision.reasonCode };
564	      }
565	
566	      // Claim the gap atomically — only if it is still open.
567	      const claimed = await tx
568	        .update(gaps)
569	        .set({ status: 'asked', updatedAt: new Date() })
570	        .where(and(eq(gaps.id, gap.id), eq(gaps.status, 'open')))
571	        .returning({ id: gaps.id });
572	      if (claimed.length === 0) {
573	        return { channelId: channel.id, decision: 'skip' as const, reasonCode: 'gap_already_claimed' };
574	      }
575	
576	      // Insert the assistant message (no employeeId — Oracle messages are
577	      // employeeId=null per the schema; role='assistant').
578	      const [interjectionMessage] = await tx
579	        .insert(messages)
580	        .values({
581	          channelId: channel.id,
582	          employeeId: null,
583	          role: 'assistant',
584	          content: drafted.text,
585	          // extractionStatus stays 'pending' default per schema; the extraction
586	          // worker queries role='user' so it'll naturally skip Oracle messages.
587	          metadataJson: {
588	            source: 'lull-interjection',
589	            gapId: gap.id,
590	            modelRunId: drafted.modelRunId,
591	            decisionReason: decision.reason,
592	          },
593	        })
594	        .returning({ id: messages.id });
595	      if (!interjectionMessage) throw new Error('failed to insert assistant message');
596	
597	      // Record the intervention.
598	      await tx.insert(oracleInterventions).values({
599	        channelId: channel.id,
600	        triggerType: 'lull_gap',
601	        relatedGapId: gap.id,
602	        interjectionMessageId: interjectionMessage.id,
603	        confidence: null,
604	        impactScore: null,
605	        wasLiveInterjection: true,
606	        reason: decision.reason,
607	      });
608	
609	      // Back-fill askedInMessageId now that the message exists.
610	      await tx
611	        .update(gaps)
612	        .set({ askedInMessageId: interjectionMessage.id })
613	        .where(eq(gaps.id, gap.id));
614	
615	      return {
616	        channelId: channel.id,
617	        decision: 'ask' as const,
618	        interjectionMessageId: interjectionMessage.id,
619	        gapId: gap.id,
620	      };
621	    });
622	  } catch (err) {
623	    const errorMessage = err instanceof Error ? err.message : String(err);
624	    console.error(`[lull-interjection] channel ${channel.id} drafting/posting failed:`, errorMessage);
625	    return {
626	      channelId: channel.id,
627	      decision: 'skip',
628	      reasonCode: 'drafting_failed',
629	      errorMessage,
630	    };
631	  }
632	}
633	
634	// ─── Top-level scheduled task ───────────────────────────────────────────────
635	export const lullInterjectionTask = schedules.task({
636	  id: 'lull-interjection',
637	  // Every minute. The cooldown + rate-cap gates inside decideLullInterjection
638	  // handle the actual interjection frequency; this just makes sure we check
639	  // often enough that a 60s lull window can fire promptly.
640	  cron: '* * * * *',
641	  maxDuration: 60 * 2,
642	  // Retries disabled: this runs every minute and posts live interjections. A
643	  // retry would re-evaluate stale channels and risk a duplicate post; the next
644	  // tick is the natural retry. (Per-task override of the global default=3.)
645	  retry: { maxAttempts: 1 },
646	  run: async (_payload, { ctx }) => {
647	    const db = getDirectDb();
648	    const client = buildOracleClient();
649	    const startedAt = new Date();
650	
651	    const [jobRun] = await db
652	      .insert(jobRuns)
653	      .values({
654	        triggerRunId: ctx.run.id,
655	        jobType: 'lull-interjection',
656	        status: 'running',
657	        startedAt,
658	      })
659	      .returning({ id: jobRuns.id });
660	    if (!jobRun) throw new Error('[lull-interjection] failed to insert job_runs row');
661	
662	    const totals = {
663	      channelsConsidered: 0,
664	      interjectionsAsked: 0,
665	      skipsByReason: {} as Record<string, number>,
666	      errors: 0,
667	    };
668	
669	    try {
670	      const lullSettings = await loadLullSettings(db);
671	      const route = await resolveInterviewRoute(db);
672	
673	      const activeChannels = await db
674	        .select({ id: channels.id, isGroupChat: channels.isGroupChat })
675	        .from(channels)
676	        .where(eq(channels.status, 'active'));
677	
678	      for (const channel of activeChannels) {
679	        totals.channelsConsidered += 1;
680	        try {
681	          const outcome = await processChannel(db, client, route, channel, lullSettings, new Date());
682	          if (outcome.decision === 'ask') {
683	            totals.interjectionsAsked += 1;
684	          } else {
685	            const code = outcome.reasonCode ?? 'unknown';
686	            totals.skipsByReason[code] = (totals.skipsByReason[code] ?? 0) + 1;
687	            if (outcome.errorMessage) totals.errors += 1;
688	          }
689	        } catch (chanErr) {
690	          totals.errors += 1;
691	          console.error(`[lull-interjection] channel ${channel.id} failed:`, chanErr);
692	        }
693	      }
694	
695	      await db
696	        .update(jobRuns)
697	        .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
698	        .where(eq(jobRuns.id, jobRun.id));
699	
700	      return { ok: true, ...totals };
701	    } catch (fatalErr) {
702	      await db
703	        .update(jobRuns)
704	        .set({
705	          status: 'failed',
706	          finishedAt: new Date(),
707	          error: fatalErr instanceof Error ? fatalErr.message : String(fatalErr),
708	        })
709	        .where(eq(jobRuns.id, jobRun.id));
710	      throw fatalErr;
711	    }
712	  },
713	});
