1	// Teams transcript DISCOVERY scan — surface already-completed meetings as
2	// pickable items (metadata only; no content pulled, no ingestion).
3	//
4	// The webhook discovers NEW meetings in real time, but only "going forward".
5	// This on-demand scan enumerates organizers and lists their existing
6	// scheduled-meeting transcripts (within Teams' retention window), upserting one
7	// `meeting_transcripts` row per transcript so they appear in the picker at
8	// /admin/transcripts. An admin then chooses which to ingest. Idempotent: re-runs
9	// upsert on transcript_id and never change an already-'ingested'/'dismissed' row.
10	//
11	// On-demand only (NOT a schedule): Trigger.dev is at its 10/10 schedule limit
12	// (AGENTS.md §10). Trigger via the picker's "Scan for recent meetings" button or
13	// the Trigger MCP: trigger_task teams-transcript-discovery-scan { "sinceDays": 14 }
14	
15	import { task } from '@trigger.dev/sdk/v3';
16	import { sql } from 'drizzle-orm';
17	import { getDirectDb } from '@oracle/db/client';
18	import { listUsers, getOnlineMeetingTranscripts } from '../lib/graph-transcripts';
19	
20	interface ScanPayload {
21	  /** How far back to scan, in days. Defaults to 14. */
22	  sinceDays?: number;
23	}
24	
25	/** Full Graph transcript id from the content URL (matches the webhook deriver). */
26	function deriveTranscriptId(contentUrl: string | null): string | null {
27	  const m = (contentUrl ?? '').match(/transcripts[('/]+([^')/]+)/i);
28	  return m && m[1] ? m[1] : null;
29	}
30	
31	export const teamsTranscriptDiscoveryScanTask = task({
32	  id: 'teams-transcript-discovery-scan',
33	  maxDuration: 60 * 8,
34	  run: async (payload: ScanPayload) => {
35	    const sinceDays = Math.max(1, Math.min(60, payload?.sinceDays ?? 14));
36	    const sinceIso = new Date(Date.now() - sinceDays * 24 * 60 * 60 * 1000).toISOString();
37	    const db = getDirectDb();
38	
39	    const organizers = await listUsers();
40	    console.log(`[teams-transcript-discovery-scan] scanning ${organizers.length} organizers since ${sinceIso}`);
41	
42	    let discovered = 0;
43	    let organizerErrors = 0;
44	    for (const organizer of organizers) {
45	      try {
46	        const transcripts = await getOnlineMeetingTranscripts(organizer.id, sinceIso);
47	        for (const t of transcripts) {
48	          const transcriptId = deriveTranscriptId(t.transcriptContentUrl);
49	          if (!transcriptId) continue;
50	          await db.execute(sql`
51	            INSERT INTO meeting_transcripts
52	              (transcript_id, meeting_id, call_id, organizer_id, organizer_name,
53	               transcript_content_url, meeting_time, status, discovered_via)
54	            VALUES
55	              (${transcriptId}, ${t.meetingId}, ${t.callId}, ${organizer.id}, ${organizer.name},
56	               ${t.transcriptContentUrl}, ${t.createdDateTime}, 'available', 'scan')
57	            ON CONFLICT (transcript_id) DO UPDATE SET
58	              meeting_id = COALESCE(EXCLUDED.meeting_id, meeting_transcripts.meeting_id),
59	              call_id = COALESCE(EXCLUDED.call_id, meeting_transcripts.call_id),
60	              organizer_id = COALESCE(EXCLUDED.organizer_id, meeting_transcripts.organizer_id),
61	              organizer_name = COALESCE(EXCLUDED.organizer_name, meeting_transcripts.organizer_name),
62	              transcript_content_url = COALESCE(EXCLUDED.transcript_content_url, meeting_transcripts.transcript_content_url),
63	              meeting_time = COALESCE(EXCLUDED.meeting_time, meeting_transcripts.meeting_time)
64	          `);
65	          discovered += 1;
66	        }
67	      } catch (err) {
68	        organizerErrors += 1;
69	        console.warn(`[teams-transcript-discovery-scan] organizer ${organizer.id} failed`, err);
70	      }
71	    }
72	
73	    console.log(`[teams-transcript-discovery-scan] upserted ${discovered} transcripts (${organizerErrors} organizer errors)`);
74	    return { sinceDays, sinceIso, organizersScanned: organizers.length, organizerErrors, transcriptsDiscovered: discovered };
75	  },
76	});
