1	// Self-contained Microsoft Graph helper for the Teams transcript workers.
2	//
3	// This lives in apps/workers (a separate Trigger.dev process from apps/web), so
4	// it intentionally re-implements the small app-only token + subscription
5	// surface rather than importing apps/web/lib/microsoft-graph.ts (cross-app
6	// imports aren't allowed). If this and the web copy drift, the web one
7	// (apps/web/lib/microsoft-graph.ts) is the reference.
8	//
9	// Required env (set in the Trigger.dev project, NOT just Vercel):
10	//   AZURE_TENANT_ID, AZURE_GRAPH_CLIENT_ID, AZURE_GRAPH_CLIENT_SECRET
11	//   TEAMS_NOTIFICATION_URL          (https://oracle.designflow.app/api/teams/notifications)
12	//   TEAMS_NOTIFICATION_PUBLIC_CERT  (base64 DER of the public cert)
13	//   TEAMS_NOTIFICATION_CERT_ID      (matches the webhook's cert id)
14	//   TEAMS_WEBHOOK_CLIENT_STATE      (shared secret; same value as the webhook)
15	
16	const GRAPH_BETA = 'https://graph.microsoft.com/beta';
17	const GRAPH_V1 = 'https://graph.microsoft.com/v1.0';
18	// Ad-hoc ("Meet Now") transcripts are only reachable via this subscription, and
19	// only on the beta endpoint (v1.0 rejects it).
20	const ADHOC_RESOURCE = 'communications/adhocCalls/getAllTranscripts';
21	// Scheduled-meeting transcripts come through a SEPARATE tenant-wide subscription.
22	// Ad-hoc and scheduled are distinct Graph resources, so each needs its own
23	// subscription (the "limit of 1" is per resource, so both can coexist).
24	const ONLINE_MEETINGS_RESOURCE = 'communications/onlineMeetings/getAllTranscripts';
25	
26	// Every transcript resource we keep a standing subscription for.
27	export const TRANSCRIPT_RESOURCES = [ADHOC_RESOURCE, ONLINE_MEETINGS_RESOURCE] as const;
28	
29	interface GraphConfig {
30	  tenantId: string;
31	  clientId: string;
32	  clientSecret: string;
33	}
34	
35	function getConfigOrNull(): GraphConfig | null {
36	  const tenantId = process.env.AZURE_TENANT_ID;
37	  const clientId = process.env.AZURE_GRAPH_CLIENT_ID;
38	  const clientSecret = process.env.AZURE_GRAPH_CLIENT_SECRET;
39	  if (!tenantId || !clientId || !clientSecret) return null;
40	  return { tenantId, clientId, clientSecret };
41	}
42	
43	let cachedToken: { token: string; refreshAt: number } | null = null;
44	
45	async function getToken(cfg: GraphConfig): Promise<string> {
46	  if (cachedToken && cachedToken.refreshAt > Date.now()) return cachedToken.token;
47	  const body = new URLSearchParams({
48	    client_id: cfg.clientId,
49	    client_secret: cfg.clientSecret,
50	    scope: 'https://graph.microsoft.com/.default',
51	    grant_type: 'client_credentials',
52	  });
53	  const res = await fetch(
54	    `https://login.microsoftonline.com/${cfg.tenantId}/oauth2/v2.0/token`,
55	    {
56	      method: 'POST',
57	      headers: { 'content-type': 'application/x-www-form-urlencoded' },
58	      body,
59	      signal: AbortSignal.timeout(10_000),
60	    },
61	  );
62	  if (!res.ok) {
63	    throw new Error(`Graph token failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
64	  }
65	  const data = (await res.json()) as { access_token: string; expires_in: number };
66	  cachedToken = {
67	    token: data.access_token,
68	    refreshAt: Date.now() + Math.max(60_000, data.expires_in * 1000 - 5 * 60 * 1000),
69	  };
70	  return cachedToken.token;
71	}
72	
73	interface SubscriptionConfig {
74	  notificationUrl: string;
75	  encryptionCertificate: string;
76	  encryptionCertificateId: string;
77	  clientState: string;
78	}
79	
80	function getSubscriptionConfigOrNull(): SubscriptionConfig | null {
81	  const notificationUrl = process.env.TEAMS_NOTIFICATION_URL;
82	  const encryptionCertificate = process.env.TEAMS_NOTIFICATION_PUBLIC_CERT;
83	  const encryptionCertificateId = process.env.TEAMS_NOTIFICATION_CERT_ID;
84	  const clientState = process.env.TEAMS_WEBHOOK_CLIENT_STATE;
85	  if (!notificationUrl || !encryptionCertificate || !encryptionCertificateId || !clientState) {
86	    return null;
87	  }
88	  return { notificationUrl, encryptionCertificate, encryptionCertificateId, clientState };
89	}
90	
91	interface GraphSub {
92	  id: string;
93	  resource: string;
94	  expirationDateTime: string;
95	  notificationUrl: string;
96	}
97	
98	export type EnsureResult = {
99	  action: 'created' | 'renewed' | 'ok' | 'skipped_no_config';
100	  resource?: string;
101	  subscriptionId?: string;
102	  expirationDateTime?: string;
103	  detail?: string;
104	};
105	
106	// Subscriptions for this resource max out near 1h. Renew to ~50m and re-up
107	// whenever the remaining lifetime drops under 20m (the cron runs every 30m).
108	const RENEW_MINUTES = 50;
109	const RENEW_IF_WITHIN_MS = 20 * 60 * 1000;
110	
111	const nextExpiry = () => new Date(Date.now() + RENEW_MINUTES * 60_000).toISOString();
112	
113	/** List our subscriptions and find the one for `resource` on our webhook. */
114	async function findSub(
115	  token: string,
116	  resource: string,
117	  notificationUrl: string,
118	): Promise<GraphSub | undefined> {
119	  const listRes = await fetch(`${GRAPH_BETA}/subscriptions`, {
120	    headers: { Authorization: `Bearer ${token}` },
121	    signal: AbortSignal.timeout(20_000),
122	  });
123	  if (!listRes.ok) {
124	    throw new Error(`list subscriptions failed (${listRes.status}): ${(await listRes.text()).slice(0, 300)}`);
125	  }
126	  const subs = ((await listRes.json()) as { value?: GraphSub[] }).value ?? [];
127	  return subs.find((s) => s.resource === resource && s.notificationUrl === notificationUrl);
128	}
