130	async function renewSub(token: string, sub: GraphSub): Promise<EnsureResult> {
131	  const res = await fetch(`${GRAPH_BETA}/subscriptions/${sub.id}`, {
132	    method: 'PATCH',
133	    headers: { Authorization: `Bearer ${token}`, 'content-type': 'application/json' },
134	    body: JSON.stringify({ expirationDateTime: nextExpiry() }),
135	    signal: AbortSignal.timeout(20_000),
136	  });
137	  if (!res.ok) {
138	    throw new Error(`renew failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
139	  }
140	  const r = (await res.json()) as GraphSub;
141	  return { action: 'renewed', resource: sub.resource, subscriptionId: r.id, expirationDateTime: r.expirationDateTime };
142	}
