144	/**
145	 * Ensure exactly one live transcript subscription for `resource` points at our
146	 * webhook: renew it if near expiry, create it if missing. Safe to call
147	 * repeatedly (the renewal cron + webhook lifecycle events both call it).
148	 *
149	 * Resource-agnostic so the same logic serves both the ad-hoc and scheduled
150	 * online-meeting transcript subscriptions.
151	 */
152	export async function ensureSubscription(resource: string): Promise<EnsureResult> {
153	  const cfg = getConfigOrNull();
154	  const subCfg = getSubscriptionConfigOrNull();
155	  if (!cfg || !subCfg) {
156	    return {
157	      action: 'skipped_no_config',
158	      resource,
159	      detail: 'Azure creds or TEAMS_* subscription env not set in the worker environment',
160	    };
161	  }
162	  const token = await getToken(cfg);
163	  const authJson = { Authorization: `Bearer ${token}`, 'content-type': 'application/json' };
164	
165	  const mine = await findSub(token, resource, subCfg.notificationUrl);
166	  if (mine) {
167	    if (Date.parse(mine.expirationDateTime) - Date.now() > RENEW_IF_WITHIN_MS) {
168	      return { action: 'ok', resource, subscriptionId: mine.id, expirationDateTime: mine.expirationDateTime };
169	    }
170	    return renewSub(token, mine);
171	  }
172	
173	  const res = await fetch(`${GRAPH_BETA}/subscriptions`, {
174	    method: 'POST',
175	    headers: authJson,
176	    body: JSON.stringify({
177	      changeType: 'created',
178	      resource,
179	      notificationUrl: subCfg.notificationUrl,
180	      lifecycleNotificationUrl: subCfg.notificationUrl,
181	      includeResourceData: true,
182	      encryptionCertificate: subCfg.encryptionCertificate,
183	      encryptionCertificateId: subCfg.encryptionCertificateId,
184	      clientState: subCfg.clientState,
185	      expirationDateTime: nextExpiry(),
186	    }),
187	    signal: AbortSignal.timeout(20_000),
188	  });
189	  if (!res.ok) {
190	    const errText = (await res.text()).slice(0, 400);
191	    // Benign race: the cron and a lifecycle event both tried to create at once,
192	    // or a previous create already succeeded ("limit of 1" per resource). Don't
193	    // fail — re-find the existing one and renew it.
194	    if (res.status === 403 && /reached its limit/i.test(errText)) {
195	      const existing = await findSub(token, resource, subCfg.notificationUrl);
196	      if (existing) return renewSub(token, existing);
197	    }
198	    throw new Error(`create failed (${res.status}): ${errText}`);
199	  }
200	  const r = (await res.json()) as GraphSub;
201	  return { action: 'created', resource, subscriptionId: r.id, expirationDateTime: r.expirationDateTime };
202	}
