223	/**
224	 * Fetch a callTranscript's content as WebVTT. Prefers the decrypted
225	 * transcriptContentUrl from the notification; falls back to building the URL
226	 * from the resource path.
227	 */
228	export async function fetchTranscriptVtt(
229	  transcriptContentUrl: string | null,
230	  resourcePath: string | null,
231	): Promise<string> {
232	  const cfg = getConfigOrNull();
233	  if (!cfg) throw new Error('Graph not configured (AZURE_* env missing)');
234	  const token = await getToken(cfg);
235	
236	  let url: string;
237	  if (transcriptContentUrl) {
238	    url = transcriptContentUrl.startsWith('http')
239	      ? transcriptContentUrl
240	      : `${GRAPH_V1}/${transcriptContentUrl.replace(/^\/+/, '')}`;
241	    if (!/[?&]\$format=/.test(url)) {
242	      url += (url.includes('?') ? '&' : '?') + '$format=text/vtt';
243	    }
244	  } else if (resourcePath) {
245	    url = `${GRAPH_V1}/${resourcePath.replace(/^\/+/, '')}/content?$format=text/vtt`;
246	  } else {
247	    throw new Error('No transcriptContentUrl or resourcePath provided');
248	  }
249	
250	  const res = await fetch(url, {
251	    headers: { Authorization: `Bearer ${token}`, Accept: 'text/vtt' },
252	    signal: AbortSignal.timeout(30_000),
253	  });
254	  if (!res.ok) {
255	    throw new Error(`transcript content fetch failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
256	  }
257	  return res.text();
258	}
