260	/**
261	 * Map of lowercased M365 display name -> primary email, for resolving Teams
262	 * transcript speakers (VTT carries display names only). Best-effort: returns an
263	 * empty map if Graph isn't configured or the call fails, so ingestion can fall
264	 * back to display-name matching. One page covers a tenant of a few hundred users.
265	 */
266	export async function listDisplayNameToEmail(): Promise<Map<string, string>> {
267	  const cfg = getConfigOrNull();
268	  if (!cfg) return new Map();
269	  const token = await getToken(cfg);
270	  const map = new Map<string, string>();
271	  let url: string | undefined =
272	    'https://graph.microsoft.com/v1.0/users?$select=displayName,mail,userPrincipalName&$top=100';
273	  while (url) {
274	    const res = await fetch(url, {
275	      headers: { Authorization: `Bearer ${token}` },
276	      signal: AbortSignal.timeout(15_000),
277	    });
278	    if (!res.ok) break; // best-effort — caller falls back to name matching
279	    const page = (await res.json()) as {
280	      value?: Array<{ displayName: string | null; mail: string | null; userPrincipalName: string | null }>;
281	      '@odata.nextLink'?: string;
282	    };
283	    for (const u of page.value ?? []) {
284	      const email = (u.mail ?? u.userPrincipalName ?? '').toLowerCase();
285	      if (u.displayName && email) map.set(u.displayName.trim().toLowerCase(), email);
286	    }
287	    url = page['@odata.nextLink'];
288	  }
289	  return map;
290	}
