292	// ─── Backfill: pull already-completed scheduled-meeting transcripts ──────────
293	//
294	// Subscriptions only "listen going forward", so to recover transcripts from
295	// meetings that already happened we enumerate organizers and ask Graph for
296	// their meeting transcripts in a time window. Idempotency is handled downstream
297	// by teams-transcript-ingestion (dedupes on transcriptId), so re-running is safe.
298	
299	/** All M365 users (id + display name) — the candidate meeting organizers. */
300	export async function listUsers(): Promise<Array<{ id: string; name: string | null }>> {
301	  const cfg = getConfigOrNull();
302	  if (!cfg) return [];
303	  const token = await getToken(cfg);
304	  const users: Array<{ id: string; name: string | null }> = [];
305	  let url: string | undefined =
306	    'https://graph.microsoft.com/v1.0/users?$select=id,displayName&$top=100';
307	  while (url) {
308	    const res = await fetch(url, {
309	      headers: { Authorization: `Bearer ${token}` },
310	      signal: AbortSignal.timeout(15_000),
311	    });
312	    if (!res.ok) {
313	      throw new Error(`list users failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
314	    }
315	    const page = (await res.json()) as {
316	      value?: Array<{ id: string; displayName: string | null }>;
317	      '@odata.nextLink'?: string;
318	    };
319	    for (const u of page.value ?? []) if (u.id) users.push({ id: u.id, name: u.displayName ?? null });
320	    url = page['@odata.nextLink'];
321	  }
322	  return users;
323	}
