333	/**
334	 * Scheduled-meeting transcripts for one organizer created at/after `sinceIso`.
335	 * Mirrors the change-notification payload shape so each result can be handed to
336	 * teams-transcript-ingestion exactly like a live notification.
337	 *
338	 * Resilient per organizer: only a first-page **403** (genuine app-access-policy
339	 * gap) throws — everything else keeps whatever was collected and stops. This
340	 * tolerates (a) Graph's beta pagination quirk where an `@odata.nextLink` comes
341	 * back with `startIndex=-1` (a 400 on page 2+), and (b) slow organizers that hit
342	 * the request timeout — neither should make one user abort the whole scan or
343	 * discard the page(s) we already have.
344	 */
345	export async function getOnlineMeetingTranscripts(
346	  organizerId: string,
347	  sinceIso: string,
348	): Promise<BackfillTranscript[]> {
349	  const cfg = getConfigOrNull();
350	  if (!cfg) return [];
351	  const token = await getToken(cfg);
352	  const out: BackfillTranscript[] = [];
353	  // The PULL endpoint is per-user: users/{id}/onlineMeetings/getAllTranscripts.
354	  // (Distinct from the tenant-wide SUBSCRIPTION resource
355	  // communications/onlineMeetings/getAllTranscripts.) See diagnose-transcripts.ps1.
356	  const endIso = new Date().toISOString();
357	  let url: string | undefined =
358	    `${GRAPH_BETA}/users/${organizerId}/onlineMeetings/getAllTranscripts(meetingOrganizerUserId='${organizerId}',startDateTime=${sinceIso},endDateTime=${endIso})`;
359	  let firstPage = true;
360	  while (url) {
361	    let res: Response;
362	    try {
363	      res = await fetch(url, {
364	        headers: { Authorization: `Bearer ${token}` },
365	        signal: AbortSignal.timeout(30_000),
366	      });
367	    } catch (err) {
368	      // Network error / timeout — keep what we have, don't abort the scan.
369	      console.warn(`[graph-transcripts] getAllTranscripts fetch error for ${organizerId}`, err);
370	      return out;
371	    }
372	    if (!res.ok) {
373	      const body = (await res.text().catch(() => '')).slice(0, 200);
374	      // A first-page 403 is a genuine access/policy gap worth surfacing.
375	      if (firstPage && res.status === 403) {
376	        throw new Error(`getAllTranscripts forbidden (403) for organizer ${organizerId}: ${body}`);
377	      }
378	      // 404 = no transcripts (expected for most users); a 400 on a nextLink is
379	      // Graph's startIndex=-1 pagination quirk. Either way, keep what we have.
380	      if (res.status !== 404) {
381	        console.warn(`[graph-transcripts] getAllTranscripts ${res.status} for ${organizerId}: ${body}`);
382	      }
383	      return out;
384	    }
385	    const page = (await res.json()) as {
386	      value?: Array<{
387	        transcriptContentUrl?: string | null;
388	        meetingId?: string | null;
389	        callId?: string | null;
390	        createdDateTime?: string | null;
391	      }>;
392	      '@odata.nextLink'?: string;
393	    };
394	    for (const t of page.value ?? []) {
395	      out.push({
396	        transcriptContentUrl: t.transcriptContentUrl ?? null,
397	        resourcePath: null,
398	        meetingId: t.meetingId ?? null,
399	        callId: t.callId ?? null,
400	        createdDateTime: t.createdDateTime ?? null,
401	      });
402	    }
403	    url = page['@odata.nextLink'];
404	    firstPage = false;
405	  }
406	  return out;
407	}
